window.vbpHistory={maxSnapshots:50,saveTimeout:null,lastState:null,init:function(){var t=this;document.addEventListener("vbp:elementChanged",function(e){t.onElementChanged(e.detail)}),document.addEventListener("vbp:beforeSave",function(e){t.createCheckpoint("Antes de guardar")}),document.addEventListener("alpine:initialized",function(){t.captureInitialState()})},captureInitialState:function(){var t=Alpine.store("vbp");t&&(this.lastState=JSON.stringify(t.elements))},onElementChanged:function(t){this.saveTimeout&&clearTimeout(this.saveTimeout);var e=this;this.saveTimeout=setTimeout(function(){e.checkForChanges()},500)},checkForChanges:function(){var t=Alpine.store("vbp");if(t){var e=JSON.stringify(t.elements);this.lastState!==e&&(this.lastState=e,t.isDirty=!0)}},createCheckpoint:function(t){var e=Alpine.store("vbp");if(e){var n={state:JSON.stringify(e.elements),nombre:t,timestamp:(new Date).toISOString()},i=this.getCheckpoints();i.push(n),i.length>10&&(i=i.slice(-10)),sessionStorage.setItem("vbp_checkpoints",JSON.stringify(i))}},getCheckpoints:function(){try{var t=sessionStorage.getItem("vbp_checkpoints");return t?JSON.parse(t):[]}catch(t){return[]}},restoreCheckpoint:function(t){var e=this.getCheckpoints()[t];if(e&&e.state){var n=Alpine.store("vbp");if(n)return n.saveToHistory(),n.elements=JSON.parse(e.state),n.isDirty=!0,!0}return!1},clearSessionHistory:function(){sessionStorage.removeItem("vbp_checkpoints")},getStats:function(){var t=Alpine.store("vbp");return t?{undoSteps:t.history.past.length,redoSteps:t.history.future.length,maxSize:t.maxHistorySize,canUndo:t.canUndo,canRedo:t.canRedo,checkpoints:this.getCheckpoints().length}:null},exportHistory:function(){var t=Alpine.store("vbp");return t?{current:t.elements,past:t.history.past,future:t.history.future,checkpoints:this.getCheckpoints()}:null}},document.addEventListener("DOMContentLoaded",function(){window.vbpHistory.init()});